import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.BqfgOMAh.js";const c=JSON.parse('{"title":"蓝图操作","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/blueprint-operations.md","filePath":"zh/guide/blueprint-operations.md"}'),l={name:"zh/guide/blueprint-operations.md"};function i(o,t,n,s,h,p){return d(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="蓝图操作" tabindex="-1">蓝图操作 <a class="header-anchor" href="#蓝图操作" aria-label="Permalink to &quot;蓝图操作&quot;">​</a></h1><p>NexusFlow 的核心能力是通过 AI 对话来操作虚幻引擎蓝图。用自然语言描述你的需求，AI 会自动分析蓝图并执行操作。</p><h2 id="ai-蓝图能力" tabindex="-1">AI 蓝图能力 <a class="header-anchor" href="#ai-蓝图能力" aria-label="Permalink to &quot;AI 蓝图能力&quot;">​</a></h2><p>NexusFlow 提供了一组内置的蓝图操作工具。这些工具由 AI 自动调用，你不需要手动触发：</p><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>读取蓝图</td><td>获取蓝图的完整结构</td></tr><tr><td>修改蓝图</td><td>添加、删除或更新蓝图元素</td></tr><tr><td>节点搜索</td><td>智能搜索可用的蓝图节点模板</td></tr><tr><td>Skill 执行</td><td>运行预定义的 UE 操作脚本</td></tr><tr><td>Python 脚本</td><td>在 UE 中执行自定义 Python 代码</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">前提条件</p><p>蓝图操作需要 UE 编辑器处于连接状态。请确认侧边栏底部状态栏显示绿色连接指示器。</p></div><h2 id="读取蓝图" tabindex="-1">读取蓝图 <a class="header-anchor" href="#读取蓝图" aria-label="Permalink to &quot;读取蓝图&quot;">​</a></h2><p>当你询问当前蓝图时，AI 会自动获取其 JSON 表示，包括：</p><ul><li>所有节点及其类型</li><li>节点之间的连线关系</li><li>变量定义和默认值</li><li>函数和事件图</li></ul><p><strong>对话示例：</strong></p><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「解释这个蓝图」</td><td>AI 读取并分析整体蓝图逻辑</td></tr><tr><td>「这个蓝图是做什么的？」</td><td>获取蓝图的功能概述</td></tr><tr><td>「列出所有变量」</td><td>查看所有变量定义</td></tr><tr><td>「EventBeginPlay 做了什么？」</td><td>解释特定的函数或事件</td></tr><tr><td>「选中的这些节点是做什么的？」</td><td>解释当前选中节点的功能</td></tr></tbody></table><p>AI 会读取蓝图结构并用清晰的语言向你解释。</p><h2 id="修改蓝图" tabindex="-1">修改蓝图 <a class="header-anchor" href="#修改蓝图" aria-label="Permalink to &quot;修改蓝图&quot;">​</a></h2><p>AI 可以对蓝图进行各种修改，包括添加、删除和编辑节点及连线。修改通过「蓝图补丁」应用，确保操作安全。</p><h3 id="节点操作" tabindex="-1">节点操作 <a class="header-anchor" href="#节点操作" aria-label="Permalink to &quot;节点操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「添加一个 Print String 节点」</td><td>创建新节点</td></tr><tr><td>「在 BeginPlay 后添加一个 2 秒延迟的 Delay 节点」</td><td>创建并连接，设置参数</td></tr><tr><td>「删除选中的节点」</td><td>移除当前选中的节点</td></tr><tr><td>「把 Delay 节点的时间改为 5 秒」</td><td>修改节点属性值</td></tr></tbody></table><h3 id="连线操作" tabindex="-1">连线操作 <a class="header-anchor" href="#连线操作" aria-label="Permalink to &quot;连线操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「把 BeginPlay 连接到 Print String」</td><td>创建节点间的连线</td></tr><tr><td>「断开 Delay 和 Print String 之间的连线」</td><td>移除连线</td></tr><tr><td>「把 GetPlayerController 的返回值连接到 Cast」</td><td>连接特定引脚</td></tr></tbody></table><h3 id="批量操作" tabindex="-1">批量操作 <a class="header-anchor" href="#批量操作" aria-label="Permalink to &quot;批量操作&quot;">​</a></h3><p>对于复杂逻辑，AI 可以在一次操作中创建多个节点和连线：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>「添加一个 Branch 节点，条件连接到 IsValid 的结果，True 时执行 Print String」</span></span>
<span class="line"><span>「创建一个简单的计时器逻辑：BeginPlay → SetTimer → 回调函数打印消息」</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">注意</p><p>AI 修改蓝图后，更改会自动反映在 UE 编辑器中。如果结果不符合预期，可以在 UE 中使用 <strong>Ctrl+Z</strong> 撤销操作。</p></div><h2 id="创建蓝图逻辑" tabindex="-1">创建蓝图逻辑 <a class="header-anchor" href="#创建蓝图逻辑" aria-label="Permalink to &quot;创建蓝图逻辑&quot;">​</a></h2><p>你可以让 AI 从零开始创建完整的蓝图逻辑：</p><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「创建一个角色移动蓝图」</td><td>构建完整的移动逻辑</td></tr><tr><td>「添加一个按下 E 键触发的输入事件」</td><td>创建输入事件处理器</td></tr><tr><td>「创建一个每 2 秒触发一次的计时器」</td><td>构建基于计时器的逻辑</td></tr><tr><td>「实现一个基本的生命值系统」</td><td>创建包含变量和逻辑的完整系统</td></tr><tr><td>「创建每 3 秒旋转 90 度的逻辑」</td><td>基于时间的变换</td></tr></tbody></table><p>AI 会根据你的描述自动创建所需的节点、变量和连线。</p><h2 id="变量管理" tabindex="-1">变量管理 <a class="header-anchor" href="#变量管理" aria-label="Permalink to &quot;变量管理&quot;">​</a></h2><p>通过对话管理蓝图变量：</p><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「创建一个 Float 变量 PlayerHealth，默认值 100」</td><td>创建带类型的变量</td></tr><tr><td>「创建一个布尔变量 IsActive」</td><td>创建简单变量</td></tr><tr><td>「把变量重命名为 PlayerHealth」</td><td>重命名现有变量</td></tr><tr><td>「把 MaxHealth 的默认值设为 100」</td><td>修改默认值</td></tr><tr><td>「删除 TempData 变量」</td><td>移除变量</td></tr></tbody></table><h2 id="函数管理" tabindex="-1">函数管理 <a class="header-anchor" href="#函数管理" aria-label="Permalink to &quot;函数管理&quot;">​</a></h2><p>管理蓝图中的自定义函数：</p><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「创建一个函数 CalculateDamage，参数 BaseDamage (Float)」</td><td>创建带参数的函数</td></tr><tr><td>「给 InitializePlayer 函数添加默认值初始化逻辑」</td><td>向现有函数添加逻辑</td></tr><tr><td>「给 GetPlayerInfo 函数添加返回值」</td><td>修改函数签名</td></tr></tbody></table><h2 id="事件管理" tabindex="-1">事件管理 <a class="header-anchor" href="#事件管理" aria-label="Permalink to &quot;事件管理&quot;">​</a></h2><p>管理蓝图事件：</p><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「添加一个 ActorBeginOverlap 事件」</td><td>添加标准事件</td></tr><tr><td>「在 EventTick 中添加旋转逻辑」</td><td>向现有事件添加逻辑</td></tr><tr><td>「创建一个自定义事件 OnPlayerDeath」</td><td>创建自定义事件</td></tr></tbody></table><h2 id="节点搜索" tabindex="-1">节点搜索 <a class="header-anchor" href="#节点搜索" aria-label="Permalink to &quot;节点搜索&quot;">​</a></h2><p>当 AI 需要查找特定类型的节点时，会使用智能搜索找到最合适的节点模板：</p><ul><li><strong>节点模板搜索</strong>：使用语义搜索查找可用的蓝图节点类型</li><li><strong>蓝图节点搜索</strong>：在当前蓝图中搜索已有节点</li></ul><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「有没有获取玩家位置的节点？」</td><td>搜索节点模板</td></tr><tr><td>「查找与碰撞检测相关的节点」</td><td>语义搜索蓝图节点</td></tr><tr><td>「有哪些数学运算节点可用？」</td><td>浏览特定类别的节点</td></tr></tbody></table><p>搜索过程是自动的——当你描述需求时，AI 会自动搜索匹配的节点来完成操作。</p><h2 id="ue-skills" tabindex="-1">UE Skills <a class="header-anchor" href="#ue-skills" aria-label="Permalink to &quot;UE Skills&quot;">​</a></h2><p>NexusFlow 包含内置的 UE Skills 系统，提供高级蓝图操作能力。AI 可以自动搜索、加载和执行相关的 Skill。</p><p>Skills 目前涵盖以下能力：</p><ul><li><strong>蓝图</strong> — 蓝图创建、管理和 60+ 节点操作</li><li><strong>资产</strong> — 资产创建、导入和管理</li><li><strong>数据</strong> — 数据表和曲线表操作</li><li><strong>光照</strong> — 光照设置和配置</li></ul><p><strong>使用示例：</strong></p><table tabindex="0"><thead><tr><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>「创建一个新的 Actor 蓝图」</td><td>AI 选择 Blueprint Skill</td></tr><tr><td>「导入这个 FBX 为静态网格」</td><td>AI 选择 Asset Skill</td></tr><tr><td>「给伤害数据表添加一行」</td><td>AI 选择 Data Skill</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">提示</p><p>你不需要了解 Skills 的实现细节。只需描述你想完成的操作，AI 会自动选择合适的 Skill。</p></div><h2 id="python-脚本执行" tabindex="-1">Python 脚本执行 <a class="header-anchor" href="#python-脚本执行" aria-label="Permalink to &quot;Python 脚本执行&quot;">​</a></h2><p>对于 Skills 未覆盖的特殊操作，AI 可以编写并执行 Python 脚本来直接操控 UE 编辑器：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>「批量重命名所有以 BP_ 开头的蓝图」</span></span>
<span class="line"><span>「导出当前关卡中所有 Actor 的位置信息」</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">安全提示</p><p>Python 脚本在 UE 编辑器中执行，拥有完整的编辑器访问权限。NexusFlow 会在执行前进行安全检查。</p></div><h2 id="高效提示技巧" tabindex="-1">高效提示技巧 <a class="header-anchor" href="#高效提示技巧" aria-label="Permalink to &quot;高效提示技巧&quot;">​</a></h2><p>遵循以下技巧可以获得更好的 AI 回复：</p><h3 id="✅-最佳实践" tabindex="-1">✅ 最佳实践 <a class="header-anchor" href="#✅-最佳实践" aria-label="Permalink to &quot;✅ 最佳实践&quot;">​</a></h3><ul><li><strong>描述具体</strong>：「在 BeginPlay 后添加一个 2 秒延迟的 Delay 节点，然后执行 Print String」比「添加一个节点」清晰得多</li><li><strong>提供背景</strong>：「我正在为射击游戏构建伤害系统」有助于 AI 理解整体目标</li><li><strong>分步完成</strong>：将复杂需求拆分为多个步骤，逐步完成并确认结果</li><li><strong>使用 UE 术语</strong>：使用准确的 UE 概念名称（如 Actor、Component、Blueprint）</li><li><strong>先选中再询问</strong>：询问前先选中特定节点，AI 能更好地理解你的意图</li></ul><h3 id="❌-应避免的做法" tabindex="-1">❌ 应避免的做法 <a class="header-anchor" href="#❌-应避免的做法" aria-label="Permalink to &quot;❌ 应避免的做法&quot;">​</a></h3><ul><li>模糊的描述，如「改一下蓝图」</li><li>在单条消息中提出过于复杂的需求</li><li>在没有打开蓝图的情况下要求蓝图操作</li></ul><div class="warning custom-block"><p class="custom-block-title">确保蓝图已打开</p><p>在请求蓝图操作之前，请确保已在 UE 编辑器中打开目标蓝图。AI 需要读取蓝图信息才能执行操作。</p></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./ai-chat">AI 对话</a> — 了解对话界面的详细功能</li><li><a href="./quick-menu">UE 快速菜单</a> — 通过右键菜单和工具栏使用 17 项 AI 操作</li><li><a href="./settings">设置说明</a> — 自定义 NexusFlow 的各项配置</li></ul>`,60)])])}const u=a(l,[["render",i]]);export{c as __pageData,u as default};
